const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

const root = path.resolve(__dirname, '..');
const outPath = path.join(root, 'src', 'web', 'react', 'reactBundle.ts');
const distDir = path.join(root, 'dist');
const firebaseHostingDir = path.join(distDir, 'firebase-hosting');
const firebaseAssetsDir = path.join(firebaseHostingDir, 'assets');
const bundlePrefix = 'webform-react';

const normalizeAssetMode = (raw) => {
  const value = (raw || '').toString().trim().toLowerCase();
  return value === 'external' || value === 'firebase' ? 'external' : 'embedded';
};

const normalizeBaseUrl = (raw) => (raw || '').toString().trim().replace(/\/+$/, '');

const inferBaseUrl = () => {
  const explicit = normalizeBaseUrl(process.env.CK_WEB_ASSET_BASE_URL);
  if (explicit) return explicit;
  const siteId = (process.env.FIREBASE_HOSTING_SITE_ID || '').toString().trim();
  return siteId ? `https://${siteId}.web.app` : '';
};

const assetMode = normalizeAssetMode(process.env.CK_WEB_ASSET_MODE || process.env.CK_REACT_BUNDLE_MODE);
const assetBaseUrl = assetMode === 'external' ? inferBaseUrl() : '';
const files = fs
  .readdirSync(distDir)
  .filter(f => f && typeof f === 'string' && f.toLowerCase().endsWith('.js'))
  .filter(f => f.toLowerCase() === `${bundlePrefix}.js` || f.toLowerCase().startsWith(`${bundlePrefix}-`))
  .sort();

const bundles = {};
const allBundles = {};
const fullFile = files.find((f) => f.toLowerCase() === `${bundlePrefix}.js`);
if (!fullFile) {
  console.error('[embed-react-bundle] Missing full bundle at', path.join(distDir, `${bundlePrefix}.js`));
  process.exit(1);
}

const fullPath = path.join(distDir, fullFile);
const fullBundle = fs.readFileSync(fullPath, 'utf8');
bundles.full = fullBundle;
allBundles.full = { content: fullBundle, fileName: fullFile };

files
  .filter((f) => f.toLowerCase() !== `${bundlePrefix}.js`)
  .forEach((fileName) => {
    const lower = fileName.toLowerCase();
    const key = lower.replace(`${bundlePrefix}-`, '').replace(/\.js$/i, '').trim();
    const bundlePath = path.join(distDir, fileName);
    if (!fs.existsSync(bundlePath)) return;
    const content = fs.readFileSync(bundlePath, 'utf8');
    allBundles[key] = { content, fileName };
    if (content === fullBundle) {
      console.info('[embed-react-bundle] Bundle matches full; skipping duplicate:', key);
      return;
    }
    bundles[key] = content;
  });

const embeddedBundles = assetMode === 'external' ? {} : bundles;
const literal = JSON.stringify(embeddedBundles, null, 2);
const hashes = Object.fromEntries(
  Object.entries(allBundles).map(([key, asset]) => [
    key,
    crypto.createHash('sha256').update(asset.content || '', 'utf8').digest('hex').slice(0, 12)
  ])
);
const hashLiteral = JSON.stringify(hashes, null, 2);
const assetManifest = Object.fromEntries(
  Object.entries(allBundles).map(([key, asset]) => {
    const hash = hashes[key] || '';
    const isFullDuplicate = key !== 'full' && asset.content === fullBundle;
    const baseName = isFullDuplicate ? bundlePrefix : asset.fileName.replace(/\.js$/i, '');
    return [
      key,
      {
        fileName: `assets/${baseName}.${hash}.js`,
        hash,
        bytes: Buffer.byteLength(asset.content || '', 'utf8')
      }
    ];
  })
);
const assetLiteral = JSON.stringify(assetManifest, null, 2);

const writeExternalAssets = () => {
  fs.rmSync(firebaseHostingDir, { recursive: true, force: true });
  fs.mkdirSync(firebaseAssetsDir, { recursive: true });
  const writtenTargets = new Set();
  Object.entries(allBundles).forEach(([key, asset]) => {
    const manifestEntry = assetManifest[key];
    if (!manifestEntry || !manifestEntry.fileName) return;
    const targetPath = path.join(firebaseHostingDir, manifestEntry.fileName);
    if (writtenTargets.has(targetPath)) return;
    writtenTargets.add(targetPath);
    fs.mkdirSync(path.dirname(targetPath), { recursive: true });
    fs.writeFileSync(targetPath, asset.content || '', 'utf8');
  });
  fs.writeFileSync(
    path.join(firebaseHostingDir, 'asset-manifest.json'),
    `${JSON.stringify(
      {
        mode: assetMode,
        baseUrl: assetBaseUrl || null,
        generatedAt: new Date().toISOString(),
        bundles: assetManifest
      },
      null,
      2
    )}\n`,
    'utf8'
  );
  console.info('[embed-react-bundle] Wrote Firebase Hosting assets to', firebaseHostingDir);
  if (!assetBaseUrl) {
    console.warn(
      '[embed-react-bundle] CK_WEB_ASSET_MODE=external is active but CK_WEB_ASSET_BASE_URL is not set. The Apps Script shell will fall back unless a script property provides it.'
    );
  }
};

if (assetMode === 'external') {
  writeExternalAssets();
}

const banner = `// Auto-generated by scripts/embed-react-bundle.js. Do not edit by hand.\n// Contains the React bundles served by the web app.\n`;
const output = `${banner}export const WEB_FORM_REACT_BUNDLES: Record<string, string> = ${literal};
export const WEB_FORM_REACT_BUNDLE: string = WEB_FORM_REACT_BUNDLES.full || '';
export const WEB_FORM_REACT_BUNDLE_HASHES: Record<string, string> = ${hashLiteral};
export const WEB_FORM_REACT_BUNDLE_HASH: string = WEB_FORM_REACT_BUNDLE_HASHES.full || '';
export const WEB_FORM_REACT_ASSET_MODE: string = ${JSON.stringify(assetMode)};
export const WEB_FORM_REACT_ASSET_BASE_URL: string = ${JSON.stringify(assetBaseUrl)};
export const WEB_FORM_REACT_ASSETS: Record<string, { fileName: string; hash: string; bytes: number }> = ${assetLiteral};
export const getReactBundle = (key?: string | null): string => {
  const k = (key || '').toString().trim().toLowerCase();
  if (!k || k === 'full') return WEB_FORM_REACT_BUNDLE;
  const direct = (WEB_FORM_REACT_BUNDLES as any)[k];
  return direct || WEB_FORM_REACT_BUNDLE;
};
export const getReactBundleHash = (key?: string | null): string => {
  const k = (key || '').toString().trim().toLowerCase();
  if (!k || k === 'full') return WEB_FORM_REACT_BUNDLE_HASH;
  const direct = (WEB_FORM_REACT_BUNDLE_HASHES as any)[k];
  return direct || WEB_FORM_REACT_BUNDLE_HASH;
};
export const getReactBundleAssetFileName = (key?: string | null): string => {
  const k = (key || '').toString().trim().toLowerCase();
  if (!k || k === 'full') return WEB_FORM_REACT_ASSETS.full?.fileName || '';
  const direct = (WEB_FORM_REACT_ASSETS as any)[k]?.fileName;
  return direct || WEB_FORM_REACT_ASSETS.full?.fileName || '';
};
`;

fs.mkdirSync(path.dirname(outPath), { recursive: true });
fs.writeFileSync(outPath, output, 'utf8');
console.info('[embed-react-bundle] Wrote React bundle metadata to', outPath, `(${assetMode})`);
